import React from "react";
import { Formik, Form, Field, ErrorMessage } from "formik";

function AddPost() {
  const initialValues = {
    title: "",
    postText: "",
    username: "",
  };

  const onSubmit = (data) => {
    console.log(data);
  };

  return (
    <div className="addPostPage">
      <Formik
        initialValues={initialValues}
        onSubmit={onSubmit}>
        <Form>
          <label>Title:</label>
          <Field
            id="inputAddPost"
            className="formInput"
            name="title"
            placeholder="Title"
          />
          <label>Post:</label>
          <Field
            id="inputAddPost"
            className="formInput"
            name="postText"
            placeholder="Text post..."
          />
          <label>Author:</label>
          <Field
            id="inputAddPost"
            className="formInput"
            name="username"
            placeholder="John"
          />

          <button type="submit">Add Post</button>
        </Form>
      </Formik>
    </div>
  );
}

export default AddPost;
